import React from 'react';
import { useCart } from '../../context/CartContext';
import styles from './ProductDetailsModal.module.css';

export default function ProductDetailsModal({ product, onClose }) {
  const { addItem } = useCart();

  if (!product) return null;

  const handleAdd = () => {
    addItem(product);
    onClose();
  };

  return (
    <div className={styles.overlay} onClick={onClose}>
      <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
        <img
          src={product.imageUrl || product.image_url || 'https://picsum.photos/seed/frukt-kray/800/500'}
          alt={product.name}
          className={styles.image}
        />

        <div className={styles.body}>
          <p className={styles.category}>{product.category?.name}</p>
          <h2 className={styles.title}>{product.name}</h2>

          <p className={styles.short}>{product.description}</p>

          <p className={styles.details}>
            {product.details || product.description}
          </p>

          <div className={styles.footer}>
            <div className={styles.price}>{product.price.toLocaleString('ru-RU')} ₽</div>
            <button className="btn btn-cherry" onClick={handleAdd}>
              В корзину
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
